  ('aviation-f975d768-moex-00094', 'aviation-f975d768', 'aviation-f975d768-moex-112-7bf35b0f', 'sub-aviation-f975d768-05', NULL, 'single_choice', '法律有強行法與任意法的區分，下列何者屬於強行法？', '["民法第1032條，關於夫妻共同財產制，對於共同財產之管理", "民法第1040條，夫妻共同財產制關係存續中取得之共同財產如何分配之規定", "民法第71條，法律行為違反法律無效之規定", "民法第1113條之7，關於意定監護之報酬規定"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:09+00:00", "source_pdf_sha1": "f79244208669", "answer_pdf_sha1": "b0e444a8d54a", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "402", "s": "0607", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識(包括中華民國憲法、法學緒論)", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 27, "answer_corrected": false, "flags": [], "civil_slug": "aviation", "civil_category": "航空通訊"}'::jsonb, NULL),
  ('aviation-f975d768-moex-00095', 'aviation-f975d768', 'aviation-f975d768-moex-112-7bf35b0f', 'sub-aviation-f975d768-05', NULL, 'single_choice', '某甲向主管機關申請營業許可，於主管機關受理後，處理程序終結前，相關法規有所修改。依舊規定 甲之申請應予許可，然依新規定甲尚須補足相關條件方有可能通過。此際主管機關應如何適用法規？', '["應適用舊法規", "應適用新法規", "由主管機關自行決定", "由主管機關之上級機關決定"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:09+00:00", "source_pdf_sha1": "f79244208669", "answer_pdf_sha1": "b0e444a8d54a", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "402", "s": "0607", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識(包括中華民國憲法、法學緒論)", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 28, "answer_corrected": false, "flags": [], "civil_slug": "aviation", "civil_category": "航空通訊"}'::jsonb, NULL),
  ('aviation-f975d768-moex-00096', 'aviation-f975d768', 'aviation-f975d768-moex-112-7bf35b0f', 'sub-aviation-f975d768-05', NULL, 'single_choice', '甲誤以為去廟裡誦經過的水果可以毒死人，於是拿誦經過的水果給乙吃，乙吃了只覺得水果特別甜美， 什麼事情都沒發生。下列關於甲刑事責任之敘述，何者正確？', '["甲為殺人之不能犯，不罰", "甲為殺人之普通未遂犯，得減輕其刑", "甲為殺人之中止犯，減輕其刑", "甲為殺人之幻覺犯，依情節減輕其刑"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:09+00:00", "source_pdf_sha1": "f79244208669", "answer_pdf_sha1": "b0e444a8d54a", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "402", "s": "0607", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識(包括中華民國憲法、法學緒論)", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 29, "answer_corrected": false, "flags": [], "civil_slug": "aviation", "civil_category": "航空通訊"}'::jsonb, NULL),
  ('aviation-f975d768-moex-00097', 'aviation-f975d768', 'aviation-f975d768-moex-112-7bf35b0f', 'sub-aviation-f975d768-05', NULL, 'single_choice', '消費者保護法中關於消費資訊之規定，下列敘述何者錯誤？', '["企業經營者有確保廣告內容真實之義務", "刊登或報導廣告之媒體經營者明知或可得而知廣告內容與事實不符者，就消費者因信賴該廣告所受 之損害，與企業經營者負連帶責任", "企業經營者對消費者保證商品或服務之品質時，應出具書面保證書", "企業經營者應依商品標示法等法令為商品之標示，進口之商品可僅附外文標示及說明書"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:09+00:00", "source_pdf_sha1": "f79244208669", "answer_pdf_sha1": "b0e444a8d54a", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "402", "s": "0607", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識(包括中華民國憲法、法學緒論)", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 30, "answer_corrected": false, "flags": [], "civil_slug": "aviation", "civil_category": "航空通訊"}'::jsonb, NULL)
